from typing import Optional
class Solution:
    def cloneGraph(self, node: Optional['Node']) -&gt; Optional['Node']:
        old2new = {}

        def clone(old: Node) -&gt; Node:
            """
            dfs-cloning approach
            """
            if old in old2new:
                return old2new[old]

            new = Node(old.val)
            old2new[old] = new
            for nb in old.neighbors:
                new.neighbors.append(
                    clone(nb)
                )

            return new

        return clone(node) if node else None
