def two_sum(nums: List[int], target: int, result: List[List[int]]) -&gt; List[List[int]]:
    seen = set()
    for j in range(len(nums)):
        complement = target - nums[j]
        if complement in seen:
            t = tuple(sorted(
                [-target, nums[j], complement]
            ))
            result.add(t)
