class Solution:
    def threeSum(self, nums: List[int]) -&gt; List[List[int]]:
        seen = set()
        result = set()
        for i in range(len(nums)-2):
            target = -nums[i]
            if nums[i] not in seen:
                two_sum(
                    nums=nums[i+1:],
                    target=target,
                    result=result
                )
                seen.add(nums[i])
        return list(result)
