    def twoSum(self, numbers: List[int], target: int) -&gt; List[int]:
        l = 0
        r = len(numbers) - 1
        while l &lt; r:
            curr_sum = numbers[l] + numbers[r]
            if curr_sum &gt; target:
                r -= 1
            elif curr_sum &lt; target:
                l += 1
            else:
                return [l+1, r+1]
