    def search(self, nums: List[int], target: int) -&gt; int:
        l = 0
        r = len(nums)-1

        while l &lt;= r:
            m = (l + r) // 2

            if nums[m] == target:
                return m

            # left sorted side
            if nums[m] &gt;= nums[-1]:
                if nums[0] &lt;= target &lt;= nums[m]:
